import { NgModule } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule, Routes } from '@angular/router';

import { CATComponent } from './cat/cat.component';
import { ITCComponent } from './itc/itc.component';
import { SECComponent } from './sec/sec.component';
import { SEGComponent } from './seg/seg.component';
import { TRCComponent } from './trc/trc.component';



const routes: Routes = [{
  path: 'cat',
  component: CATComponent
}, {
  path: 'itc',
  component: ITCComponent
}, {
  path: 'sec',
  component: SECComponent
}, {
  path: 'seg',
  component: SEGComponent
}, {
  path: 'trc',
  component: TRCComponent
}];

@NgModule({
  declarations: [],
  imports: [
    CommonModule,
    RouterModule.forChild(routes)
  ],
  exports: [RouterModule]
})
export class PCTRoutingModule { }
